var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"제가 너무 늦었죠, 사장님?","JPN":"遅れてしまってすみません、社長。","ENG":"I'm sorry I'm late, Boss.","TWN":"老闆，不好意思，等很久了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아이들이랑 술래잡기하다 보니 시간이 벌써 이렇게 됐네요…….","JPN":"子どもたちと鬼ごっこをしていたら、もうこんな時間に……","ENG":"I lost track of the time while playing hide-and-seek with the girls.","TWN":"我和孩子們玩捉迷藏玩到忘了時間……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"마지막에 아인이 잡혀 줘서 다행이었어요. 이제 저로서는 아이들을 따라갈 힘이 없거든요.","JPN":"最後にアインが捕まってくれて助かりました。もう私じゃ、あの子たちに追いつく体力もなくて。","ENG":"Thank God, Eins let me catch her in the end. I no longer have enough energy to follow them around.","TWN":"幸好最後艾茵有讓我抓到，畢竟現在的我根本沒有力氣追著孩子跑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이렇게 다 같이 모여서 놀 수 있는 것도……. 오래 가진 못하겠지만요.","JPN":"こうしてみんなで集まって遊べる時も……長くはないでしょう。","ENG":"And I don't have much time left... to play with them.","TWN":"像這樣可以聚在一起玩的時間……也不多了吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아뇨, 사장님. 저는 그래도 괜찮아요.","JPN":"いいえ、社長。私は平気です。","ENG":"No, Boss, I'm still okay.","TWN":"沒事！老闆，我沒事的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"웃으면서 뛰어다니는 아이들을 보고 있으면, 제가 선택한 길이 옳다는 게 느껴지거든요.","JPN":"笑顔で走り回る子どもたちを見ていると、自分の選んだ道が正しかったと思えるんです。","ENG":"Looking at them running around, laughing happily, I once again realize I've done the right thing.","TWN":"只要看到孩子們奔跑時的笑容，就會覺得我選的路是正確的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……그래서 더 고마워요, 사장님.","JPN":"……だから、社長にはなおさら感謝の気持ちでいっぱいです。","ENG":"So, thank you, Boss.","TWN":"……所以，真的很謝謝老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"사실은 많이 무서웠어요. 꿈 속에서 찾은 답에 아인이랑 츠바이의 안전을 맡겼으니까요.","JPN":"実はかなり不安だったんです。夢の中で見つけた答えに、アインとツヴァイの安全を委ねたわけですから。","ENG":"To tell you the truth, I was scared to death to leave their fate to the answer I'd found in my dreams.","TWN":"要把艾茵&茨粨的安全交給夢裡找到的答案，老實說我是很害怕的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아이들을 받아 주신 분이 사장님이라서, 정말……. 다행…….","JPN":"子どもたちを受け入れてくれた方が社長で、本当に……よかっ……","ENG":"I'm so glad that it was you... who accepted... the girls...","TWN":"但接收她們的人是老闆，我真的覺得……很幸運……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"죄송해요. 오늘은 조금, 지쳤나 봐요. 숨이……. 갑자기 가빠져서…….","JPN":"すみません。今日は少し、疲れてしまったようです。息が……急に苦しくなって……","ENG":"I'm sorry. I must be exhausted today. Suddenly I can't... breathe...","TWN":"抱歉，我今天可能有點累，有點喘……喘不過氣……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼呼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이런 모습, 괜히 보여 드려서 걱정 끼쳐 드리고 싶지 않았는데…….","JPN":"こんな見苦しい姿を見せて心配をかけたくなかったのに……","ENG":"I didn't want you to see me like this and get worried...","TWN":"真不想讓老闆看到我這副模樣為我擔心……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그래도 저, 꼭 사장님과 함께하기로 결심했어요.","JPN":"それでも私、この先も必ず社長と一緒にいると心に決めました。","ENG":"But Boss, I want to be with you.","TWN":"不過我已經決定要和老闆一起。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"짧은 시간이라도, 제게 주신 행복을 사장님과도 나누고 싶으니까요.","JPN":"短い時間だとしても、私に与えてくださった幸せを社長と分かち合いたいのです。","ENG":"I want to share this happiness with you for however long I have left to live.","TWN":"雖然很短暫，但我想要和老闆分享我的小確幸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"어리광으로 들리시겠지만……. 이런 저라도, 받아 주실래요?","JPN":"わがままに聞こえるかもしれませんが……こんな私でも、受け入れてくれますか？","ENG":"I don't want to sound needy, but... would you accept me?","TWN":"我有個不情之請……老闆你可以接受這樣的我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};